var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"레비아, 멈춰.","JPN":"レヴィア、待て。","ENG":"Levia, stop!","TWN":"莉維亞，停下來。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"왜요? 설마 유리 언니 있는 데로 돌아가자고 하게요?","JPN":"何ですか？　まさかユリさんのところに戻ろうとでもいうつもりですか？","ENG":"Why? You're not thinking of heading back for Yuri, are you?","TWN":"幹嘛？不會是要回去找悠麗姊姊吧？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"하여간 눈치는 빠르군. 이유리가 네 반이라도 닮으면 좋았을 텐데.","JPN":"まったく、勘がいいな。カスカベがお前に半分でも似てくれたら助かるんだが。","ENG":"Guess you're not as slow as I thought. If only Yuri could catch on half as fast as you.","TWN":"反應還真快，真希望李悠麗有你一半聰明就好。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"녀석이 아니면 베로니카를 상대할 수가 없어. 반드시 데리고 가야 한다.","JPN":"あいつじゃないとベロニカの相手は無理だ。必ず連れて帰らなければ。","ENG":"She's the only one who can go against Veronica. We need to take her with us.","TWN":"要是沒那傢伙，我們是打不贏貝洛妮卡的，一定要帶上她。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"에이, 짠한 동료애를 기대했는데 삭막한 말씀을 하시네.","JPN":"もう、涙ぐましい仲間意識を期待してたのにドライなんですね。","ENG":"Oof, and here I was hoping you'd say something about comradery.","TWN":"哎呀，我還期待有灑狗血的同胞愛呢，結果還真冷漠。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"겸사겸사야. 정에 매여선 이 짓도 오래 못 해.","JPN":"ついでだ。情にかまけているとこの仕事も長くはやれない。","ENG":"A little bit of both, okay? But you won't last long in this industry if you cling onto feelings.","TWN":"差不多就好，放太多感情是沒辦法幹這行的。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"좋아요. 대신 창자에 구멍 나도 제 탓 하기 없기예요?","JPN":"いいですよ。その代わりに、お腹に穴が開いても私を責めないでくださいね？","ENG":"Okay! But don't blame me if you end up getting a hole in your stomach.","TWN":"好吧，不過到時候你腸子破洞可別怪我喔！"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"이제 그만 포기하시지? 아직도 상황 파악이 안 돼?","JPN":"もうあきらめたら？　まだ状況が把握できないの？","ENG":"Give up already! Can't you see you lost?","TWN":"放棄吧？你還搞不清楚狀況嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그런 데 쓸 주변머리는 옛날에 다 갖다 버렸어. 잡아 족쳐야 할 괴물들이 한둘이어야지.","JPN":"そういう場合の要領の良さは遥か昔に捨てた。捕まえて殺すべき化け物が多すぎてね。","ENG":"I threw that kind of attitude away a long time ago. You see, there are too many monsters in this world that need killing.","TWN":"我從很久以前就已經扔掉這種變通的能力，畢竟要對付的怪物太多。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"우린 그쪽이 해야 할 일을 대신 해 주고 있는 거야. 감사하는 시늉이라도 하지 그래.","JPN":"私たちは本来ならあなたたちがやるべき仕事を代わりにやってあげてるんだ。感謝してほしいな。","ENG":"You know, we're basically doing your job for you! Shouldn't you be thanking us?","TWN":"我們是在幫你們做你們該做的事，好歹也假裝感謝一下吧？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"자기들 멋대로 법을 무시하고 다니면서 말이야?","JPN":"自分勝手に法を無視して？","ENG":"For what? Running around and disobeying the law?","TWN":"你們藐視法律還要我們表示感謝嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"애초에 그딴 식으로 도와달라고 한 적도 없어!","JPN":"そもそもそんな風に助けてくれなんて頼んだ覚えもない！","ENG":"Also, we never asked for your help!","TWN":"我們從未拜託你們用這種方式幫忙過！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님, 조심하세요! 공범들이 주위에 남아 있을지도 몰라요!","JPN":"警視様、気をつけてください！　共犯者がこの辺りに残ってるかもしれません！","ENG":"Major, watch out! Her accomplices might be lurking nearby!","TWN":"警正，小心！周圍可能還有共犯！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"아니! 이건 공권력의 위신이 걸린 문제야! 강소영 경위!","JPN":"いいえ！　これは公権力の威信にかかわる問題よ！　マエカワ警部補！","ENG":"No, Lieutenant Kang! This is a matter of preserving public authority!","TWN":"不！這可是攸關公權力威信的問題！姜素英員警！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아아, 결국 또 뻔한 도발에 넘어가 버리시네……","JPN":"ああ、結局またあからさまな挑発に乗せられて……","ENG":"Ugh... There she goes taking the bait again...","TWN":"哀哀，又落入對方激將法的圈套裡……"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};